		{ObjectMeta: metav1.ObjectMeta{Name: "custom-a"}},
		{ObjectMeta: metav1.ObjectMeta{Name: "custom-b"}},
	}

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(drivers[0], drivers[1], drivers[2]).Build()

	requests := getNVIDIADriversToReconcile(context.Background(), client)
	require.ElementsMatch(t, []reconcile.Request{
		{NamespacedName: types.NamespacedName{Name: "default"}},
		{NamespacedName: types.NamespacedName{Name: "custom-a"}},
		{NamespacedName: types.NamespacedName{Name: "custom-b"}},
	}, requests)
}

func TestReconcileConflictSetsNotReadyState(t *testing.T) {
	scheme := runtime.NewScheme()
	require.NoError(t, nvidiav1alpha1.AddToScheme(scheme))
	require.NoError(t, gpuv1.AddToScheme(scheme))

	driver := &nvidiav1alpha1.NVIDIADriver{
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-driver",
			Namespace: "default",
		},
		Status: nvidiav1alpha1.NVIDIADriverStatus{
			State: nvidiav1alpha1.Ready,
		},
	}

	cp := &gpuv1.ClusterPolicy{
		ObjectMeta: metav1.ObjectMeta{Name: "default"},
		Spec: gpuv1.ClusterPolicySpec{
			Driver: gpuv1.DriverSpec{
				UseNvidiaDriverCRD: ptr.To(true),
			},
		},
	}

	client := fake.NewClientBuilder().WithScheme(scheme).WithObjects(cp, driver).Build()
	updater := &FakeConditionUpdater{}

	reconciler := &NVIDIADriverReconciler{
		Client:           client,
		Scheme:           scheme,
		conditionUpdater: updater,
		nodeSelectorValidator: &FakeNodeSelectorValidator{
			CustomError: errors.New("conflicting selector"),
		},
	}

	req := ctrl.Request{
		NamespacedName: types.NamespacedName{
			Name:      driver.Name,
			Namespace: driver.Namespace,
		},
	}

	_, err := reconciler.Reconcile(context.Background(), req)
	require.NoError(t, err)
	require.Equal(t, nvidiav1alpha1.NotReady, updater.LastErrorState)
}

